#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T, N, K;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        int P[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &P[i]);
        }
        qsort(P, N, sizeof(int), compare);
        for (int i = 0; i < K; i++) {
            printf("%d ", i + 1);
        }
        printf("\n");
    }
    return 0;
}

