#include <iostream>
#include <algorithm>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T, N, K;
    cin >> T;
    while (T--) {
        cin >> N >> K;
        int P[N];
        for (int i = 0; i < N; i++) {
            cin >> P[i];
        }
        sort(P, P + N);
        for (int i = 0; i < K; i++) {
            cout << i + 1 << " ";
        }
        cout << endl;
    }
    return 0;
}

code.Java:
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] P = new int[N];
            for (int i = 0; i < N; i++) {
                P[i] = sc.nextInt();
            }
            Arrays.sort(P);
            for (int i = 0; i < K; i++) {
                System.out.print((i + 1) + " ");
            }
            System.out.println();
        }
    }
}

